// Tests for code fixtures.
#![allow(clippy::too_many_lines)]
use e2e_rust::{assertions, resolve_document};
use kreuzberg::KreuzbergError;
use kreuzberg::core::config::ExtractionConfig;
#[test]
fn test_code_javascript_basic() {
    // Smoke test: JavaScript source code file extraction

    let document_path = resolve_document("code/app.js");
    if !document_path.exists() {
        println!(
            "Skipping code_javascript_basic: missing document at {}",
            document_path.display()
        );
        return;
    }
    let config = ExtractionConfig::default();

    let result = match kreuzberg::extract_file_sync(&document_path, None, &config) {
        Err(KreuzbergError::MissingDependency(dep)) => {
            println!("Skipping code_javascript_basic: missing dependency {dep}", dep = dep);
            return;
        }
        Err(KreuzbergError::UnsupportedFormat(fmt)) => {
            println!(
                "Skipping code_javascript_basic: unsupported format {fmt} (requires optional tool)",
                fmt = fmt
            );
            return;
        }
        Err(KreuzbergError::Parsing { message: ref msg, .. }) => {
            println!("Skipping code_javascript_basic: parsing dependency unavailable: {msg}");
            return;
        }
        Err(err) => panic!("Extraction failed for code_javascript_basic: {err:?}"),
        Ok(result) => result,
    };

    assertions::assert_expected_mime(&result, &["text/x-source-code"]);
    assertions::assert_min_content_length(&result, 10);
    assertions::assert_content_contains_all(&result, &["class Application", "export function", "import"]);
}

